import{_ as l,o as e,c as i,a0 as r}from"./chunks/framework.SERXgfZn.js";const u=JSON.parse('{"title":"服务协议","description":"","frontmatter":{"sidebar":false,"aside":false,"prev":false,"next":false},"headers":[],"relativePath":"service-agreement.md","filePath":"service-agreement.md"}'),o={name:"service-agreement.md"};function t(n,a,h,s,p,d){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="服务协议" tabindex="-1">服务协议 <a class="header-anchor" href="#服务协议" aria-label="Permalink to &quot;服务协议&quot;">​</a></h1><p>最后更新日期：2026年6月30日</p><p>生效日期：2026年7月1日</p><p>欢迎使用 NovaAPI。</p><p>本《 服务协议》（以下简称“本协议”）由您与NovaAPI（以下简称“我们”或“平台”）订立。本协议适用于您访问或使用 NovaAPI 网站、控制台、应用程序编程接口（API）、软件开发工具包（SDK）、文档、垂类 Agent及相关服务（统称“服务”）。</p><p>使用本平台的服务即表示您同意接受本协议的约束。如果您代表公司、学校、研究机构或其他组织使用服务，您声明您有权使该组织受本协议约束。</p><h1 id="一、平台服务说明" tabindex="-1">一、平台服务说明 <a class="header-anchor" href="#一、平台服务说明" aria-label="Permalink to &quot;一、平台服务说明&quot;">​</a></h1><ol><li>NovaAPI 提供统一接口、鉴权、计量计费以及特定垂类 API 与 Agent 服务。除明确标记为 NovaAPI 自营的能力外，基础模型通常由第三方模型供应商提供。</li><li>您理解并同意，输入可能被传输给您选择的模型供应商及其必要的基础设施服务商，以完成请求。</li><li>模型名称、版本、上下文长度、速率限制、价格、功能和可用性等可能因上游调整而变化。我们会在合理可行的范围内提前通知重大变化；紧急安全事件、上游即时变更或法律要求除外。</li><li>第三方模型的使用还可能受其专项使用政策约束，您不得通过 NovaAPI 从事上游明确禁止的用途。</li><li>除双方另有书面 SLA 外，我们不承诺服务始终可用、无错误或任何模型永久存在。</li><li>我们可进行计划维护、紧急维护、容量限制和安全升级，并在合理可行时提前通知。</li><li>支付、云计算、内容分发、监控、客户支持及模型能力可能由第三方提供。第三方服务可能有独立条款。我们将审慎选择供应商并采取合同与安全措施，但不控制第三方的全部系统和政策。因第三方服务造成的责任，按照适用法律、本协议及相关 SLA 分配。</li></ol><h1 id="二、账户注册与使用" tabindex="-1">二、账户注册与使用 <a class="header-anchor" href="#二、账户注册与使用" aria-label="Permalink to &quot;二、账户注册与使用&quot;">​</a></h1><ol><li>您必须达到所在地订立本协议所需的法定年龄；个人用户原则上应年满 18 周岁。</li><li>您应提供真实、准确、完整且保持更新的注册、账单和联系信息。</li><li>如法律、支付机构、反欺诈规则、制裁与出口管制要求或合理风险控制等需要，我们可要求进行电子邮箱验证、手机验证、企业验证或其他必要的身份与资质核验。</li><li>您应妥善保管密码、API Key、子密钥和其他凭证，不得公开或共享给无权人员.</li><li>对于因您未采取合理保护措施导致的未授权调用，您原则上承担相应费用。发现异常后，您应立即吊销或轮换密钥并通知我们。</li><li>未经我们书面同意，您不得批量注册、转售账户、出租 API Key、规避地域限制，或以虚假身份、代理地址等方式掩盖实际使用地。</li></ol><h1 id="三、计费与充值" tabindex="-1">三、计费与充值 <a class="header-anchor" href="#三、计费与充值" aria-label="Permalink to &quot;三、计费与充值&quot;">​</a></h1><ol><li>服务可采用按量付费、预付余额、订阅、最低消费或订单约定的其他模式。具体计价单位、输入与输出 Token 计算方式、缓存计费、图像或音频计费及汇率，以调用时模型页面和订单为准。</li><li>平台计量系统及上游返回的用量记录是结算的重要依据。若记录存在明显错误，您可在相关账单生成后 30 日内提出异议；我们将结合网关记录和上游记录复核。</li><li>充值余额仅用于购买服务，除适用法律另有要求外，不计利息、不可转让且不能兑换现金。</li><li><strong>退款规则</strong>：由于 API 及 Agent 服务的特殊性，一旦充值成功，<strong>账户余额原则上不提供退款服务</strong>，但余额可永久用于本平台的任何服务消费。</li><li>如因上游成本、汇率、税费或市场条件变化需要调价，新价格仅对生效后的调用适用。我们将在合理可行时至少提前 7 日公告；上游即时调整、严重汇率波动或紧急法律要求下，可缩短通知期，但不会追溯增加已完成调用的费用。</li><li>如您启用自动充值或订阅，应明确授权扣款金额、触发条件与支付方式，并可在后续扣款前关闭。拒付、恶意退款或支付欺诈可能导致账户暂停，并不免除已实际发生的费用。</li></ol><h1 id="四、可接受使用规则" tabindex="-1">四、可接受使用规则 <a class="header-anchor" href="#四、可接受使用规则" aria-label="Permalink to &quot;四、可接受使用规则&quot;">​</a></h1><p>在使用本平台服务时，您同意不会使用服务进行任何违法或未经授权的活动，包括且不限于：</p><ol><li>侵犯他人的知识产权、隐私、个人信息、商业秘密或其他合法权益；</li><li>生成、传播虚假信息、有害内容或违反法律法规的内容；</li><li>开发、部署或传播恶意软件，未经授权侵入系统、窃取凭证、造成拒绝服务，或提供可直接造成现实网络伤害的操作性帮助；</li><li>绕过安全措施、速率限制、计费、地域限制、内容过滤或模型供应商规则，干扰平台或其他用户正常使用；</li><li>对服务或模型进行法律禁止或上游条款禁止的逆向工程、模型提取、权重窃取、批量抓取或竞争性训练；</li><li>未经书面授权转售、分许可、贴牌或向第三方提供共享 API Key;</li><li>您应遵守数据最小化原则。科研、医疗、教育、人力资源或其他敏感场景应优先去标识化，并根据需要完成伦理审查、数据保护影响评估、个人信息保护影响评估或机构审批。</li></ol><h1 id="五、隐私保护" tabindex="-1">五、隐私保护 <a class="header-anchor" href="#五、隐私保护" aria-label="Permalink to &quot;五、隐私保护&quot;">​</a></h1><p>我们重视用户的隐私保护。关于我们如何收集和保护您的账户基础信息，请详细参阅我们的《隐私政策》。</p><h1 id="六、知识产权" tabindex="-1">六、知识产权 <a class="header-anchor" href="#六、知识产权" aria-label="Permalink to &quot;六、知识产权&quot;">​</a></h1><ol><li>NovaAPI 及其许可方拥有平台软件、网关、界面、文档、商标、设计和服务改进的权利。除本协议明示许可外，不向您转让任何平台知识产权。</li><li>在法律允许且不违反模型供应商条款的范围内，我们不对您的输出主张所有权。输出是否享有著作权、是否可独占使用，以及对第三方权利的影响，取决于适用法律、模型条款和具体事实。</li><li>服务可能包含开源软件，其使用受相应开源许可证约束。</li><li>如果您自愿提供建议或反馈，您授权我们为改进服务而免费使用该反馈，但我们不会因此取得您的用户内容或保密信息的所有权。</li></ol><h1 id="七、暂停与终止" tabindex="-1">七、暂停与终止 <a class="header-anchor" href="#七、暂停与终止" aria-label="Permalink to &quot;七、暂停与终止&quot;">​</a></h1><ol><li>在存在安全风险、未付款、欺诈、违法、违反本协议或上游紧急要求时，我们可暂停受影响的密钥、模型或账户。除紧急情况、法律禁止或可能妨碍调查外，我们会说明主要原因并提供申诉渠道。</li><li>您可停止使用服务并申请注销账户。注销前应导出账单和必要记录、撤销密钥并处理未完成订单。</li><li>若我们无因终止收费服务或永久停止全部服务，我们将按照相关法律法规处理您的账户余额和个人信息。</li></ol><h1 id="八、免责声明" tabindex="-1">八、免责声明 <a class="header-anchor" href="#八、免责声明" aria-label="Permalink to &quot;八、免责声明&quot;">​</a></h1><p>在适用法律允许的最大范围内，服务按“现状”和“可用”提供。我们不保证输出准确、完整、不侵权或适合特定目的，不保证任何模型、功能、价格或地区持续可用。法律不允许排除的保证不受本条影响。</p><h1 id="九、适用法律与争议解决" tabindex="-1">九、适用法律与争议解决 <a class="header-anchor" href="#九、适用法律与争议解决" aria-label="Permalink to &quot;九、适用法律与争议解决&quot;">​</a></h1><p>如本协议的任何条款被视作无效或无法执行，则上述条款可被分离，其他条款仍具有法律效力。本协议的标题仅为方便阅读所设，不对具体条款的定义、限制、解释或描述其范围或界限。</p><p>本协议之效力、解释、变更、执行与争议解决等均适用中华人民共和国大陆地区法律。</p><p>因本公司与您就本协议的签订、履行或解释发生争议，双方应努力友好协商解决。双方应先将争议提交 <a href="mailto:support@novaapis.com" target="_blank" rel="noreferrer">support@novaapis.com</a> 友好协商，协商期为收到书面通知后 30 日。</p><p>如协商不成，本公司和您均同意向上海仲裁委员会提起仲裁。</p><h1 id="十、协议变更与通知" tabindex="-1">十、协议变更与通知 <a class="header-anchor" href="#十、协议变更与通知" aria-label="Permalink to &quot;十、协议变更与通知&quot;">​</a></h1><p>本平台有权对本服务协议及相应的服务规则内容进行变更，并将网页公告、电子邮件、站内信、短信等方式予以公告或通知；若您在本服务协议内容变更后继续使用本服务的，表示您已充分阅读、理解并接受修改后的内容，也将遵循修改后的协议内容。</p><p>在您的账户注销或经双方协商一致终止网站服务的，本服务协议终止。如果任何条款在性质上或其他方面理应地在此协议终止时继续存在，那么应视为继续存在的条款，这些条款包括但不局限于陈述保证条款、违约责任与免责条款、法律适用与管辖条款。</p><h1 id="十一、联系我们" tabindex="-1">十一、联系我们 <a class="header-anchor" href="#十一、联系我们" aria-label="Permalink to &quot;十一、联系我们&quot;">​</a></h1><p>如您对本服务条款、账单或技术接入有任何疑问，请随时与我们联系。</p><p>电子邮箱：support@novaapis.com</p>',34)])])}const m=l(o,[["render",t]]);export{u as __pageData,m as default};
